const LOGO_SJO_HIST = "data:image/png;base64,";
const LOGO_SAC_HIST = "data:image/png;base64,";
const LOGO_HAY_HIST = "data:image/png;base64,";
const LOGO_CON_HIST = "data:image/png;base64,";

// Get logo for team at a given year (year optional, defaults to current)
const getTeamLogo = (team, year) => {
  // Year parameter is kept for backward compatibility with existing callers
  // but is ignored — every team now uses a single canonical logo regardless
  // of year.
  if (!team) return null;
  if (team === "NOR") return LOGO_CON_HIST; // NOR redirects to CON's logo
  if (team === "SRA") return LOGO_SRA_HIST;
  if (team === "CON") return LOGO_CON_HIST;
  if (TEAM_LOGOS_CURRENT[team]) return TEAM_LOGOS_CURRENT[team];
  return null;
};

// Franchise mapping: some historical team codes are treated as the same
// franchise as a current team for counting purposes. NOR -> CON (2005 code
// for Sacramento/Concord area). SRA -> PLE (San Ramon became Pleasanton).
// All other codes stay as-is.
const FRANCHISE_MAP = { NOR: "CON", SRA: "PLE" };
const toFranchise = (team) => FRANCHISE_MAP[team] || team;

// Ordinal formatter: 1st, 2nd, 3rd, 4th, ..., 11th, 12th, 13th, ..., 21st, 22nd
const ordinal = (n) => {
  if (n == null) return "";
  const s = ["th", "st", "nd", "rd"];
  const v = n % 100;
  return n + (s[(v - 20) % 10] || s[v] || s[0]);
};

// Back-compat: TEAM_LOGOS[team] returns current logo
const TEAM_LOGOS = new Proxy({}, {
  get: (_, team) => getTeamLogo(team),
});

const TEAM_2005_NAMES = {
  HAY: "West (Hayward)", CON: "North (Concord + Sacramento)", SJO: "South (San Jose)", SRA: "East (San Ramon)"
};
const getTeamDisplay = (team, year) => {
  if (year === 2005 && TEAM_2005_NAMES[team]) return TEAM_2005_NAMES[team];
  return TEAM_NAMES[team] || team;
};

const TeamLogo = ({ team, year, size = 24, className = "" }) => {
  const logo = getTeamLogo(team, year);
  const colors = {
    HAY: { bg: "#2563eb", text: "#ffffff" },
    SJO: { bg: "#7f1d1d", text: "#ffffff" },
    MOD: { bg: "#dc2626", text: "#ffffff" },
    PDF: { bg: "#0d9488", text: "#ffffff" },
    SAC: { bg: "#7c3aed", text: "#ffffff" },
    PLE: { bg: "#facc15", text: "#000000" },
    CON: { bg: "#065f46", text: "#ffffff" },
    SRA: { bg: "#b91c1c", text: "#ffffff" },
    CIS: { bg: "#16a34a", text: "#ffffff" },
    SJK: { bg: "#eab308", text: "#ffffff" },
    NOR: { bg: "#065f46", text: "#ffffff" },
  };
  const c = colors[team] || { bg: "#888", text: "#fff" };
  if (logo) {
    return <img src={logo} alt={team} style={{ width: size, height: size, objectFit: "contain" }} className={`flex-shrink-0 ${className}`} />;
  }
  return (
    <div className={`rounded flex items-center justify-center flex-shrink-0 ${className}`} style={{ width: size, height: size, backgroundColor: c.bg }}>
      <span style={{ fontSize: Math.max(7, size * 0.35), color: c.text }} className="font-black">{team}</span>
    </div>
  );
};

