// Team Share bonus: rewards players who produced a disproportionate share of their
// team's total Game Score, weighted by team win rate. Only applies at 20%+ share.
// Formula: (share - 0.20) * 10 * (0.5 + win_rate)
// No cap. Requires 5+ games and positive team total GmSc.
function getShareBonus(r) {
  if (r.g < 5) return 0;
  const teamKey = r.team + "-" + r.year;
  const teamGmsc = TEAM_GMSC_BY_YEAR[teamKey];
  if (!teamGmsc || teamGmsc <= 0) return 0;
  const playerKey = r.player + "-" + r.team + "-" + r.year;
  const playerGmsc = PLAYER_GMSC_BY_TEAM_YEAR[playerKey] || 0;
  const share = playerGmsc / teamGmsc;
  if (share < 0.20) return 0;
  const ts = TEAM_SEASONS[teamKey];
  if (!ts) return 0;
  const totalG = ts.w + ts.l;
  if (totalG <= 0) return 0;
  const winRate = ts.w / totalG;
  const winFactor = 0.5 + winRate;
  return (share - 0.20) * 10 * winFactor;
}

function getPlayerShare(r) {
  const teamKey = r.team + "-" + r.year;
  const teamGmsc = TEAM_GMSC_BY_YEAR[teamKey];
  if (!teamGmsc || teamGmsc <= 0) return 0;
  const playerKey = r.player + "-" + r.team + "-" + r.year;
  const playerGmsc = PLAYER_GMSC_BY_TEAM_YEAR[playerKey] || 0;
  return playerGmsc / teamGmsc;
}

// Get team performance multiplier for AI score
function getTeamMultiplier(team, year) {
  const key = team + "-" + year;
  const ts = TEAM_SEASONS[key];
  if (!ts) return 1.0;
  let mult = 1.0;
  if (ts.final === "Champ") mult *= 1.10;
  else if (ts.final === "Finals") mult *= 1.03;
  else if (ts.final === "Missed") mult *= 0.95;
  // Losing record penalty stacks
  if (ts.l > ts.w) mult *= 0.95;
  return mult;
}

function rankScore(r, maxG, leagueAvgTS) {
  // Scoring: raw PPG + efficiency bonus
  const scoring = r.ppg;
  const tsDiff = r.ts - leagueAvgTS;
  const effMult = tsDiff >= 0 ? 1.0 : 1.5;
  const effBonus = r.fga > 0 ? tsDiff * r.ppg * effMult : 0;
  // Rebounds, assists, defense
  const rebVal = r.rpg * 1.0;
  const astVal = r.apg * 1.6;
  const defVal = (r.spg + r.bpg) * 1.8;
  const foulPen = (r.foul / Math.max(r.g, 1)) * 0.3;
  // Raw per-game value
  const rawPG = scoring + effBonus + rebVal + astVal + defVal - foulPen;
  // GP factor: 8+ games = full credit, then stepped down, continues below 5
  let gpFactor = 1.0;
  if (r.g >= 8) gpFactor = 1.0;
  else if (r.g === 7) gpFactor = 0.95;
  else if (r.g === 6) gpFactor = 0.85;
  else if (r.g === 5) gpFactor = 0.70;
  else if (r.g === 4) gpFactor = 0.55;
  else if (r.g === 3) gpFactor = 0.40;
  else if (r.g === 2) gpFactor = 0.25;
  else if (r.g === 1) gpFactor = 0.15;
  else gpFactor = 0;
  return { rawPG: Math.round(rawPG * 10) / 10, gpFactor, total: Math.round(rawPG * gpFactor * 10) / 10, lowG: r.g < 5 };
}

function getLeagueAvgTS(year) {
  const season = DATA.filter(r => r.year === year && r.g >= 1);
  const totalPts = season.reduce((s, r) => s + r.pts, 0);
  const totalFGA = season.reduce((s, r) => s + r.fga, 0);
  const totalFTA = season.reduce((s, r) => s + r.fta, 0);
  return totalPts / Math.max(2 * (totalFGA + 0.44 * totalFTA), 1);
}

// Compute AI Score for every player-season
const _leagueTS = {};
YEARS.forEach(y => { _leagueTS[y] = getLeagueAvgTS(y); });
const _maxGByYear = {};
YEARS.forEach(y => { _maxGByYear[y] = Math.max(...DATA.filter(d => d.year === y).map(d => d.g)); });
DATA.forEach(r => {
  const sc = rankScore(r, _maxGByYear[r.year], _leagueTS[r.year]);
  const teamMult = getTeamMultiplier(r.team, r.year);
  const shareBonus = getShareBonus(r);
  const baseScore = sc.total * teamMult;
  r.aiScore = Math.round((baseScore + shareBonus) * 10) / 10;
  r.teamMult = teamMult;
  r.lowG = sc.lowG;
  r.teamShare = getPlayerShare(r);
  r.shareBonus = Math.round(shareBonus * 10) / 10;
});
// Compute AI rank per season
YEARS.forEach(y => {
  const season = DATA.filter(d => d.year === y).sort((a, b) => b.aiScore - a.aiScore);
  season.forEach((r, i) => { r.aiRank = i + 1; });
});

// Overwrite CSV-baked `award` field for 2005-2023 based on Claude's computed First/Second Team.
// 2024-2025 retain their CSV (player vote) values.
(() => {
  const MVP_PICKS = {
    2005: ["SHEHATA GEORGE", "HAY"], 2006: ["SHEHATA GEORGE", "HAY"],
    2007: ["YOUSSEF ANDREW", "HAY"], 2008: ["MULUGETA YONI", "SRA"],
    2009: ["SHEHATA GEORGE", "HAY"], 2010: ["SHEHATA GEORGE", "HAY"],
    2011: ["ABRAHAM PETER", "SJO"], 2012: ["BADROOS ANDREW", "SAC"],
    2013: ["ISHAK ANDREW", "SJO"], 2014: ["ISHAK ANDREW", "SJO"],
    2015: ["ISHAK ANDREW", "SJO"], 2016: ["ISHAK ANDREW", "SJO"],
    2017: ["AWAD BISHOY", "SAC"], 2018: ["BADROOS ANDREW", "SAC"],
    2019: ["SHACKER MARK", "SJO"], 2021: ["ISHAK ANDREW", "PDF"],
    2022: ["KELADA ANTHONY", "SAC"], 2023: ["ISHAK ANDREW", "PDF"],
  };
  const bestRegSeasonTeam = (year) => {
    const teams = {};
    Object.entries(TEAM_SEASONS).forEach(([k, v]) => {
      const [tn, yr] = k.split("-");
      if (parseInt(yr) === year) {
        const total = v.w + v.l;
        teams[tn] = { wr: total > 0 ? v.w / total : 0, w: v.w };
      }
    });
    const entries = Object.entries(teams);
    if (!entries.length) return null;
    entries.sort((a, b) => b[1].wr - a[1].wr || b[1].w - a[1].w);
    return entries[0][0];
  };
  const claudePicksYears = Object.keys(MVP_PICKS).map(Number);
  claudePicksYears.forEach(y => {
    // Reset award field for all players this year whose current award is one we'd overwrite
    DATA.filter(r => r.year === y).forEach(r => {
      if (r.award === "MVP" || r.award === "All-PCAL" || r.award === "Second Team") {
        r.award = "";
      }
    });
    const eligible = DATA.filter(r => r.year === y && r.g >= 5);
    if (!eligible.length) return;
    const picked = new Set();
    const firstTeam = [];
    const addPick = (p) => {
      const k = p.player + "|" + p.team;
      if (picked.has(k)) return;
      picked.add(k);
      firstTeam.push(p);
    };
    // Rule 1: highest Total GmSc
    const byTotal = [...eligible].sort((a, b) => b.gmSc - a.gmSc);
    if (byTotal.length) addPick(byTotal[0]);
    // Rule 2: highest Avg GmSc min 7G
    const min7 = eligible.filter(r => r.g >= 7).sort((a, b) => b.avgGmSc - a.avgGmSc);
    for (const cand of min7) {
      if (!picked.has(cand.player + "|" + cand.team)) { addPick(cand); break; }
    }
    // Rule 3: highest AI on best regular-season team.
    // Satisfied automatically if the top-AI player on that team is already picked.
    const bestTeam = bestRegSeasonTeam(y);
    if (bestTeam) {
      const teamPlayers = eligible.filter(r => r.team === bestTeam).sort((a, b) => b.aiScore - a.aiScore);
      if (teamPlayers.length) {
        const topOnBest = teamPlayers[0];
        if (!picked.has(topOnBest.player + "|" + topOnBest.team)) {
          addPick(topOnBest);
        }
        // else: criterion already satisfied by an earlier pick, skip to Rule 4
      }
    }
    // Rule 4: fill to 5 by next highest AI
    const byAI = [...eligible].sort((a, b) => b.aiScore - a.aiScore);
    for (const cand of byAI) {
      if (firstTeam.length >= 5) break;
      if (!picked.has(cand.player + "|" + cand.team)) addPick(cand);
    }
    // MVP: must be in First Team
    const mp = MVP_PICKS[y];
    const mvpRecord = mp ? firstTeam.find(p => p.player === mp[0] && p.team === mp[1]) : null;
    // Second Team: next 5 by Total GmSc from remaining
    const byTotalDesc = [...eligible].sort((a, b) => b.gmSc - a.gmSc);
    const secondTeam = byTotalDesc.filter(r => !picked.has(r.player + "|" + r.team)).slice(0, 5);
    // Apply awards
    firstTeam.forEach(p => {
      if (mvpRecord && p.player === mvpRecord.player && p.team === mvpRecord.team) {
        p.award = "MVP";
      } else {
        p.award = "All-PCAL";
      }
    });
    secondTeam.forEach(p => { p.award = "Second Team"; });
  });
})();

// Per-year leader sets for each stat. Ties count as leaders.
// Per-game stats qualify at g>=5. Percentage stats require attempts>=15.
// Game-count leaders (G) are determined from the max G that year.
const LEADERS_BY_YEAR = (() => {
  const out = {};
  const statsConfig = [
    { key: "ppg",      qual: r => r.g >= 5 },
    { key: "rpg",      qual: r => r.g >= 5 },
    { key: "apg",      qual: r => r.g >= 5 },
    { key: "spg",      qual: r => r.g >= 5 },
    { key: "bpg",      qual: r => r.g >= 5 },
    { key: "avgGmSc",  qual: r => r.g >= 5 },
    { key: "aiScore",  qual: r => r.g >= 5 },
    { key: "ts",       qual: r => r.g >= 5 && r.fga >= 15 },
    { key: "fgPct",    qual: r => r.g >= 5 && r.fga >= 15 },
    { key: "tpPct",    qual: r => r.g >= 5 && r.tpa >= 15 },
    { key: "ftPct",    qual: r => r.g >= 5 && r.fta >= 15 },
    { key: "g",        qual: r => r.g >= 1 },
  ];
  YEARS.forEach(y => {
    const season = DATA.filter(r => r.year === y);
    out[y] = {};
    statsConfig.forEach(({ key, qual }) => {
      const eligible = season.filter(qual);
      if (!eligible.length) { out[y][key] = new Set(); return; }
      const maxVal = Math.max(...eligible.map(r => r[key]));
      // tolerate tiny FP noise for percentages
      const leaders = new Set();
      eligible.forEach(r => {
        if (Math.abs(r[key] - maxVal) < 0.0001) leaders.add(r.player + "|" + r.team);
      });
      out[y][key] = leaders;
    });
  });
  return out;
})();
function isLeader(r, stat) {
  const key = r.player + "|" + r.team;
  return LEADERS_BY_YEAR[r.year] && LEADERS_BY_YEAR[r.year][stat] && LEADERS_BY_YEAR[r.year][stat].has(key);
}

