// Shorthand labels for POTW nomination categories
const potwShort = (label) => {
  if (!label) return "—";
  if (label.includes("Game Score") || label.includes("Highest")) return "GmSc";
  if (label.includes("Scorer")) return "PTS";
  if (label.includes("Rebounder")) return "REB";
  if (label.includes("Playmaker")) return "PLY";
  if (label.includes("Winner")) return "W.E.";
  return "GmSc";
};

// Remap week numbers for years with data issues
function remapWeek(g) {
  if (g[20] === 2021 && g[3] === 5) {
    // Split W5 into two: Group A stays W5, Group B becomes W6
    const groupA = new Set(["PDF-SJO","SJO-PDF","SJO-CIS","CIS-SJO","PDF-SAC","SAC-PDF","CON-SAC","SAC-CON"]);
    return groupA.has(`${g[1]}-${g[2]}`) ? 5 : 6;
  }
  if (g[20] === 2021 && g[3] === 6) return 6; // old W6 single entry merges into new W6
  if (g[20] === 2021 && g[3] === 7) return 7; // playoffs stay W7
  return g[3];
}

function computePOTWNominees(year) {
  const played = GAME_LOG.filter(g => g[6] === 1 && g[20] === year).map(g => {
    const newWeek = remapWeek(g);
    return newWeek !== g[3] ? [...g.slice(0,3), newWeek, ...g.slice(4)] : g;
  });
  const weeks = [...new Set(played.map(g => g[3]))].sort((a,b) => a - b)
    .filter(w => played.filter(g => g[3] === w).length >= 10);
  const result = {};

  weeks.forEach(w => {
    const pMap = {};
    played.filter(g => g[3] === w).forEach(g => {
      if (!pMap[g[0]]) pMap[g[0]] = { name: g[0], team: g[1], games: [] };
      pMap[g[0]].games.push(g);
    });

    const players = Object.values(pMap);
    players.forEach(p => {
      p.pts = p.games.reduce((s,g) => s+g[7], 0);
      p.reb = p.games.reduce((s,g) => s+g[8], 0);
      p.stl = p.games.reduce((s,g) => s+g[9], 0);
      p.ast = p.games.reduce((s,g) => s+g[10], 0);
      p.blk = p.games.reduce((s,g) => s+g[11], 0);
      p.fgm = p.games.reduce((s,g) => s+g[12], 0);
      p.fga = p.games.reduce((s,g) => s+g[13], 0);
      p.ftm = p.games.reduce((s,g) => s+g[14], 0);
      p.fta = p.games.reduce((s,g) => s+g[15], 0);
      p.tpm = p.games.reduce((s,g) => s+g[16], 0);
      p.tpa = p.games.reduce((s,g) => s+g[17], 0);
      p.gmSc = p.games.reduce((s,g) => s+g[19], 0);
      p.sab = p.stl + p.ast + p.blk;
      p.results = p.games.map(g => {
        const teamPts = played.filter(og => og[1] === g[1] && og[2] === g[2] && og[3] === w).reduce((s,og) => s+og[7], 0);
        const oppPts = played.filter(og => og[1] === g[2] && og[2] === g[1] && og[3] === w).reduce((s,og) => s+og[7], 0);
        return { opp: g[2], teamPts, oppPts, won: teamPts > oppPts, type: g[5], gmSc: Math.round(g[19] * 10) / 10 };
      });
      // Sort: R first, then P (semi), then C (final)
      const typeOrd = { R: 0, X: 1, P: 2, C: 3 };
      p.results.sort((a,b) => (typeOrd[a.type] || 0) - (typeOrd[b.type] || 0));
      p.allWins = p.results.length > 0 && p.results.every(r => r.won);
    });

    const chosen = new Set();
    const nominees = [];

    const byGmSc = [...players].sort((a,b) => b.gmSc - a.gmSc);
    const byPts = [...players].sort((a,b) => b.pts - a.pts || b.gmSc - a.gmSc);
    const byReb = [...players].sort((a,b) => b.reb - a.reb || b.gmSc - a.gmSc);
    const bySAB = [...players].sort((a,b) => b.sab - a.sab || b.gmSc - a.gmSc);

    // 1. Highest GmSc
    const n1 = byGmSc.find(x => !chosen.has(x.name));
    if (n1) { chosen.add(n1.name); nominees.push({ ...n1, label: "Highest Game Score", reason: "Highest combined game score this week" }); }

    // 2. Top scorer (only if they ARE the #1 scorer)
    const n2 = byPts.find(x => !chosen.has(x.name));
    if (n2 && byPts.indexOf(n2) === 0) {
      chosen.add(n2.name); nominees.push({ ...n2, label: "Top Scorer", reason: `Led the league in scoring with ${n2.pts} points` });
    } else {
      const fb = byGmSc.find(x => !chosen.has(x.name));
      if (fb) { chosen.add(fb.name); nominees.push({ ...fb, label: "Next Best Game Score", reason: `Next highest overall game score (${fb.gmSc.toFixed(1)})` }); }
    }

    // 3. Top rebounder (only if they ARE the #1 rebounder)
    const n3 = byReb.find(x => !chosen.has(x.name));
    if (n3 && byReb.indexOf(n3) === 0) {
      chosen.add(n3.name); nominees.push({ ...n3, label: "Top Rebounder", reason: `Led the league in rebounding with ${n3.reb} boards` });
    } else {
      const fb = byGmSc.find(x => !chosen.has(x.name));
      if (fb) { chosen.add(fb.name); nominees.push({ ...fb, label: "Next Best Game Score", reason: `Next highest overall game score (${fb.gmSc.toFixed(1)})` }); }
    }

    // 4. Top playmaker (only if they ARE the #1 playmaker)
    const n4 = bySAB.find(x => !chosen.has(x.name));
    if (n4 && bySAB.indexOf(n4) === 0) {
      chosen.add(n4.name); nominees.push({ ...n4, label: "Top Playmaker", reason: `Most combined steals + assists + blocks (${n4.sab})` });
    } else {
      const fb = byGmSc.find(x => !chosen.has(x.name));
      if (fb) { chosen.add(fb.name); nominees.push({ ...fb, label: "Next Best Game Score", reason: `Next highest overall game score (${fb.gmSc.toFixed(1)})` }); }
    }

    // 5. Winner's edge — highest GmSc with 2+ wins (must have played 2+ games)
    const twoWinPlayers = [...players].filter(p => p.results.length >= 2 && p.results.every(r => r.won)).sort((a,b) => b.gmSc - a.gmSc);
    const existingWinner = nominees.find(nom => twoWinPlayers.length > 0 && nom.name === twoWinPlayers[0].name);
    if (existingWinner) {
      existingWinner.winnerEdge = true;
      const n5b = byGmSc.find(x => !chosen.has(x.name));
      if (n5b) { chosen.add(n5b.name); nominees.push({ ...n5b, label: "Next Best Game Score", reason: `Next highest overall game score (${n5b.gmSc.toFixed(1)})` }); }
    } else {
      const n5 = twoWinPlayers.find(x => !chosen.has(x.name));
      if (n5) {
        chosen.add(n5.name); nominees.push({ ...n5, label: "Winner's Edge", reason: `Highest game score among players who won both games` });
      } else {
        const n5b = byGmSc.find(x => !chosen.has(x.name));
        if (n5b) { chosen.add(n5b.name); nominees.push({ ...n5b, label: "Next Best Game Score", reason: `Next highest overall game score (${n5b.gmSc.toFixed(1)})` }); }
      }
    }

    nominees.sort((a,b) => b.gmSc - a.gmSc);

    const lowestNominee = nominees.length > 0 ? nominees[nominees.length - 1].gmSc : 0;
    const leapfrogged = byGmSc
      .filter(p => !chosen.has(p.name) && p.gmSc > lowestNominee)
      .map(p => ({ ...p }));

    // POTW = highest game score
    const potw = byGmSc[0] || null;

    const yearLocs = YEAR_LOCATIONS[year] || [];
    const loc = yearLocs[w - 1] || {};
    result[w] = { nominees, leapfrogged, potw, isPlayoff: played.filter(g => g[3] === w && g[5] !== "R").length > 0, date: loc.date || "", location: loc.location || "", city: loc.city || "" };
  });
  return result;
}

